func main() {
    s := "hello"

    // Rune iteration (correct for Unicode)
    for i, ch := range s {
        fmt.Printf("%d: %c\n", i, ch)
    }

    // Byte access (fine for ASCII)
    fmt.Println(s[0])        // 104 (byte value of 'h')
    fmt.Println(string(s[0])) // h
    fmt.Println(len(s))       // 5
}

