func main() {
    var sb strings.Builder
    words := []string{"hello", "world", "go"}
    for i, w := range words {
        if i > 0 {
            sb.WriteString(" ")
        }
        sb.WriteString(w)
    }
    fmt.Println(sb.String())  // hello world go
}

